class Solution {
public:
    int hardestWorker(int n, vector<vector<int>>& logs) {
        int maxTime = 0, res = 0;
        for (int i = 1; i < logs.size(); i++) {
            int time = logs[i][1] - logs[i-1][1];
            if (time > maxTime) {
                maxTime = time;
                res = logs[i][0];
            } else if (time == maxTime) {
                res = min(res, logs[i][0]);
            }
        }
        return res;
    }
};
```
